local function CatchAble(wr, LandingPos, TimeOfProjectileFlight)
	--// Detect character/model
	local char

	if typeof(wr) == "Instance" and wr:IsA("Model") then
		-- NPC (Model with Humanoid)
		char = wr
	elseif wr and wr.Character then
		-- Player
		char = wr.Character
	end

	if not char then
		return false
	end

	--// Get HRP + Humanoid safely
	local hrp = char:FindFirstChild("HumanoidRootPart")
	local humanoid = char:FindFirstChild("Humanoid")

	if not hrp or not humanoid then
		return false
	end

	--// Do catch math
	local Dist = (hrp.Position - LandingPos).Magnitude
	local WalkSpeed = humanoid.WalkSpeed
	local DiveCorrect = 0.31

	local TimeNeeded = (Dist / WalkSpeed) - DiveCorrect

	if TimeNeeded <= TimeOfProjectileFlight then
		return true
	elseif Dist == 0 then
		return true
	else
		return false
	end
end
	
