UIS.InputEnded:Connect(function(input, gp)
	if gp then return end

	if input.KeyCode == Enum.KeyCode.LeftShift then
		if jumpBoostEnabled then
			pendingBoost = true  -- next jump gets buffed
		end
	end
end)

