--// Smooth Plastic Material Toggle System

local smoothOn = false
local originalMaterials = {} -- stores part -> original material

local function setSmoothPlastic()
	for _, obj in ipairs(workspace:GetDescendants()) do
		if obj:IsA("BasePart") then
			originalMaterials[obj] = obj.Material
			obj.Material = Enum.Material.SmoothPlastic
		end
	end
end

local function restoreMaterials()
	for part, mat in pairs(originalMaterials) do
		if part and part:IsA("BasePart") then
			part.Material = mat
		end
	end
	originalMaterials = {} -- reset table
end

--// Main update function
local function updateSmoothState()
	if smoothOn then
		setSmoothPlastic()
	else
		restoreMaterials()
	end
end


